package main

import (
    "fmt"
    "io"
    "os"
)

func main() {
    // ---- os package ----
    fmt.Println("=== os and File I/O ===")

    // ---- Getting environment variables ----
    home := os.Getenv("HOME")
    if home != "" {
        fmt.Println("HOME:", home)
    }

    // ---- Getting command line arguments ----
    args := os.Args
    fmt.Println("Args:", args)

    // ---- Working directory ----
    dir, err := os.Getwd()
    if err == nil {
        fmt.Println("Working dir:", dir)
    }

    // ---- File operations ----

    // ---- Create a file ----
    file, err := os.Create("test.txt")
    if err != nil {
        fmt.Println("Error creating file:", err)
        return
    }
    defer file.Close()

    // ---- Write to file ----
    _, err = file.WriteString("Hello, File I/O!\n")
    if err != nil {
        fmt.Println("Error writing:", err)
        return
    }

    _, err = file.WriteString("Second line\n")
    if err != nil {
        fmt.Println("Error writing:", err)
        return
    }

    fmt.Println("File created and written")

    // ---- Read from file ----
    data, err := os.ReadFile("test.txt")
    if err != nil {
        fmt.Println("Error reading:", err)
        return
    }

    fmt.Println("\nFile contents:")
    fmt.Println(string(data))

    // ---- Read line by line ----
    file2, err := os.Open("test.txt")
    if err != nil {
        fmt.Println("Error opening:", err)
        return
    }
    defer file2.Close()

    buf := make([]byte, 1024)
    for {
        n, err := file2.Read(buf)
        if err == io.EOF {
            break
        }
        if err != nil {
            fmt.Println("Error reading:", err)
            break
        }
        fmt.Print(string(buf[:n]))
    }

    // ---- File info ----
    info, err := os.Stat("test.txt")
    if err != nil {
        fmt.Println("Error getting file info:", err)
        return
    }

    fmt.Println("\nFile info:")
    fmt.Println("Name:", info.Name())
    fmt.Println("Size:", info.Size(), "bytes")
    fmt.Println("Mode:", info.Mode())
    fmt.Println("IsDir:", info.IsDir())
    fmt.Println("ModTime:", info.ModTime())

    // ---- Check if file exists ----
    _, err = os.Stat("test.txt")
    if err == nil {
        fmt.Println("File exists")
    } else if os.IsNotExist(err) {
        fmt.Println("File does not exist")
    }

    // ---- Delete file ----
    err = os.Remove("test.txt")
    if err != nil {
        fmt.Println("Error deleting:", err)
        return
    }
    fmt.Println("File deleted")

    // ---- Create directory ----
    err = os.Mkdir("testdir", 0755)
    if err != nil {
        fmt.Println("Error creating dir:", err)
        return
    }
    fmt.Println("Directory created")

    // ---- Remove directory ----
    err = os.Remove("testdir")
    if err != nil {
        fmt.Println("Error deleting dir:", err)
        return
    }
    fmt.Println("Directory deleted")
}

